// Tab IDs that were added AFTER the Role-Based Tab Access feature shipped.
// A tenant whose role permissions were saved before these tabs existed has
// an `allowedTabs` list that simply doesn't mention them. Without special
// handling those tabs would vanish for that tenant until an admin re-saves.
// NB: STAFF_ACCESS is intentionally NOT in this set. It is hard-gated to
// OWNER / SUPER_ADMIN / CTO above this layer — the nav-rendering code
// drops it from the tabs array entirely for non-owner roles, and the
// content branch renders an Access-Denied panel if a non-owner reaches
// it via direct URL. Putting it in ALWAYS_VISIBLE_TABS would expose it
// to any non-owner with an ancient unmarked allowedTabs list — which is
// the exact bug the founder flagged on 7 Jun 2026 ("STAFF_ACCESS should
// only be visible to Business owner. this is critical.").
const ALWAYS_VISIBLE_TABS = new Set<string>(['INVENTORY', 'DELIVERY', 'LOYALTY', 'ROSTER', 'TIMESHEET', 'FRONT_OFFICE_REPORTS', 'CHANNEL_MANAGER', 'PUBLIC_BOOKING_PAGE']);

// Versioned sentinels appended by savePermissions() to every PARTIAL
// restriction list. Each marker stamps the list as "configured through the
// Role Access UI of THIS generation, with full knowledge of every tab that
// existed at that time" — so the runtime can tell deliberate exclusions
// (admin really doesn't want this tab) from "the tab didn't exist yet".
//
//   PERMS_V2_MARKER  — first marker, shipped with the INVENTORY/DELIVERY
//                       Role Access fix. List with V2 only = admin knew
//                       about INVENTORY+DELIVERY but NOT about LOYALTY /
//                       ROSTER / TIMESHEET.
//   PERMS_V3_MARKER  — current generation, shipped with Phase 3. List
//                       with V3 = admin knew about every tab below.
//
// The markers are NOT real tabs — they never appear in RESTAURANT_TABS /
// HOTEL_TABS, are stripped before the admin grid renders, and are ignored
// by every consumer except isTabVisible().
const PERMS_V2_MARKER = '__perm_v2__';
const PERMS_V3_MARKER = '__perm_v3__';

// Tabs that did NOT exist when V2 markers were being written. If a list
// has a V2 marker but no V3 marker, the admin couldn't have informed
// themselves about these tabs (because they hadn't been built yet) — so
// we grandfather them visible. Once the admin re-saves through the V3 UI,
// the V3 marker is appended and any exclusion sticks.
const TABS_INTRODUCED_AFTER_V2 = new Set<string>(['LOYALTY', 'ROSTER', 'TIMESHEET']);

// Decide whether a dashboard tab should be visible for a tenant, given the
// tenant's saved allowedTabs list.
//   • allowedTabs null / empty       → no restriction → everything visible
//   • tab explicitly present         → visible
//   • V3 marker present              → admin's exclusion was fully informed
//                                       → respect it, hide the tab
//   • V2 marker present (no V3)      → admin's exclusion was informed only
//                                       about pre-LOYALTY tabs; grandfather
//                                       any tab added since (LOYALTY,
//                                       ROSTER, TIMESHEET)
//   • no marker                      → ancient legacy list (saved before
//                                       the marker existed); grandfather
//                                       every tab in ALWAYS_VISIBLE_TABS
function isTabVisible(id: string, allowedTabs: string[] | null | undefined): boolean {
  if (id === 'HOME') return true;   // launchpad is the default landing — always reachable
  if (!allowedTabs || allowedTabs.length === 0) return true;
  if (allowedTabs.includes(id)) return true;
  if (allowedTabs.includes(PERMS_V3_MARKER)) {
    // Fully-informed exclusion as of the current UI generation
    return false;
  }
  if (allowedTabs.includes(PERMS_V2_MARKER)) {
    // V2-era save — admin couldn't have informed themselves about
    // post-V2 tabs. Grandfather them; respect exclusions of pre-V2 tabs.
    return TABS_INTRODUCED_AFTER_V2.has(id);
  }
  // Pre-V2 (truly ancient) — grandfather everything in ALWAYS_VISIBLE_TABS.
  if (ALWAYS_VISIBLE_TABS.has(id)) return true;
  return false;
}

// ─── CSV helpers — shared by inventory module ─────────────────────────────────
// downloadCsv / parseCsv used by Ingredients, Suppliers, POs, GRNs sub-views
// for export + import. Handles quoted fields, embedded commas, escaped quotes.

function csvEscape(v: any): string {
  const s = v == null ? '' : String(v);
  return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
}
function csvMoney(v: any): string {
  const n = Number(v);
  return Number.isFinite(n) ? n.toFixed(2) : '';
}
// ─── IST date helpers ─────────────────────────────────────────────────────
// This app serves India hotels; "today" and date labels must be the
// Asia/Kolkata calendar day. toISOString() returns the UTC day, which is a
// day behind for the first 5.5h of every IST day — the source of repeated
// off-by-one bugs. Use these instead of `new Date().toISOString().slice(0,10)`.
function todayISO(): string {
  return new Date().toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10);
}
function toISTDate(v: any): string {
  if (!v) return '';
  const d = v instanceof Date ? v : new Date(v);
  if (isNaN(d.getTime())) return '';
  return d.toLocaleString('en-CA', { timeZone: 'Asia/Kolkata' }).slice(0, 10);
}
// ─── Room-type inventory math (single source of truth) ─────────────────────
// Used by the Calendar (V1 + V2) Types view AND the OTA Inventory report so
// the on-screen "X of N left" counts and the numbers loaded onto OTA channels
// can never drift apart (a drift here = overbooking / underselling).
function sellableRoomCount(rooms: any[]): number {
  return (rooms || []).filter(r => r.status !== 'MAINTENANCE' && r.status !== 'BLOCKED').length;
}
function availableOnDate(rooms: any[], grid: any, date: string): number {
  let avail = 0;
  for (const r of (rooms || [])) {
    if (r.status === 'MAINTENANCE' || r.status === 'BLOCKED') continue;
    const st = String(grid?.[r.id]?.[date]?.status || 'VACANT').toUpperCase();
    if (st === 'VACANT') avail++;
  }
  return avail;
}
// Colour tier for an availability count: sold-out (red), low ≤25% (amber),
// open (green). avail===0 always wins — matches the calendar headers.
function inventoryTier(avail: number, sellable: number): { bg: string; fg: string } {
  if (avail === 0) return { bg: '#fde2e7', fg: '#9f1239' };
  if (sellable >= 4 && avail <= Math.ceil(sellable * 0.25)) return { bg: '#fef3c7', fg: '#92400e' };
  return { bg: '#e9f7ef', fg: '#1f513f' };
}
// Per-room-type sellable-count matrix for the OTA Inventory report.
function computeOtaInventoryMatrix(data: any): { dates: string[]; rows: Array<{ tid: string; name: string; sellable: number; counts: number[] }> } {
  const dates: string[] = data?.dates || [];
  const rooms: any[] = data?.rooms || [];
  const grid: any = data?.grid || {};
  const typeName = new Map<string, string>();
  for (const t of (data?.room_types || [])) typeName.set(String(t.id), t.name);
  const byType = new Map<string, any[]>();
  for (const r of rooms) {
    const k = r.type_id ? String(r.type_id) : '__uncat__';
    if (!byType.has(k)) byType.set(k, []);
    byType.get(k)!.push(r);
  }
  const rows = Array.from(byType.entries()).map(([tid, trooms]) => ({
    tid,
    // Resolve category from room_types via type_id only — never room.type
    // (legacy free-text that still holds the stale default 'standard').
    name: typeName.get(tid) || 'Uncategorised',
    sellable: sellableRoomCount(trooms),
    counts: dates.map(d => availableOnDate(trooms, grid, d)),
  }));
  rows.sort((a, b) => a.name.localeCompare(b.name));
  return { dates, rows };
}

// ─── Booking lifecycle state (client request 7 Jun 2026) ──────────────────
// Maps the DB status (BOOKED / CHECKED_IN / CHECKED_OUT / CANCELLED) +
// check_out_date into the four-state Stay-View vocabulary owners + staff
// know from competing PMSes:
//
//   Assigned       — pre-arrival ("BOOKED")
//   Checked-in     — guest in-house ("CHECKED_IN", check_out > today)
//   Checking out   — departure day ("CHECKED_IN", check_out === today)
//   Checked-out    — gone ("CHECKED_OUT")
//   Cancelled      — never came ("CANCELLED")
//
// Zero schema change — derived purely from existing columns so the 39
// places that read `status === 'CHECKED_IN'` keep working unchanged.
// The "Checking out" state is auto-flagged on departure day; receptionist
// doesn't need to click a transition button. When the cashier finally
// settles + clicks Check Out, the existing /checkout endpoint flips
// CHECKED_IN → CHECKED_OUT and the row falls off the "Checking out"
// derivation.
export type BookingLifecycle = 'ASSIGNED' | 'CHECKED_IN' | 'CHECKING_OUT' | 'CHECKED_OUT' | 'CANCELLED';
export function bookingLifecycleState(booking: any, todayIso?: string): BookingLifecycle {
  const today = (todayIso || new Date().toISOString().slice(0, 10)).slice(0, 10);
  const status = String(booking?.status || '').toUpperCase();
  if (status === 'CANCELLED') return 'CANCELLED';
  if (status === 'CHECKED_OUT') return 'CHECKED_OUT';
  if (status === 'BOOKED') return 'ASSIGNED';
  if (status === 'CHECKED_IN') {
    const co = String(booking?.check_out_date || '').slice(0, 10);
    if (co && co <= today) return 'CHECKING_OUT';
    return 'CHECKED_IN';
  }
  return 'ASSIGNED';
}
// Visual treatment per lifecycle state. Mirrors the calendar cellPalette
// so the booking-list pill, the calendar cell, and the Stay-View legend
// all read the same.
export const LIFECYCLE_PALETTE: Record<BookingLifecycle, { bg: string; text: string; border: string; label: string }> = {
  ASSIGNED:     { bg: 'bg-rose-50',    text: 'text-rose-700',    border: 'border-rose-200',    label: 'Assigned' },
  CHECKED_IN:   { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-emerald-200', label: 'Checked-in' },
  CHECKING_OUT: { bg: 'bg-amber-50',   text: 'text-amber-800',   border: 'border-amber-300',   label: 'Checking out' },
  CHECKED_OUT:  { bg: 'bg-slate-100',  text: 'text-slate-600',   border: 'border-slate-300',   label: 'Checked-out' },
  CANCELLED:    { bg: 'bg-stone-100',  text: 'text-stone-500',   border: 'border-stone-300',   label: 'Cancelled' },
};

function downloadCsv(filename: string, header: string[], rows: any[][]): void {
  const lines = [header.map(csvEscape).join(','), ...rows.map(r => r.map(csvEscape).join(','))];
  const csv = lines.join('\n');
  const blob = new Blob(['﻿' + csv], { type: 'text/csv;charset=utf-8' });  // BOM for Excel ₹
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}

// Adults-capacity workflow (12 Jun 2026) — given the TOTAL adults staying and
// the room's capacity (= adults included in the base rate), derive the
// chargeable extra adults and the total headcount. Mirrors the server's
// deriveAdultExtras so the live preview matches what the backend will store.
//   extra_adults = max(0, adults − capacity);  num_guests = adults + children
function deriveOccupancy(adults: number, capacity: number, childMat: number, childNoMat: number): { extra_adults: number; num_guests: number } {
  const a   = Math.max(1, Math.floor(Number(adults)   || 1));
  const cap = Math.max(1, Math.floor(Number(capacity) || 1));
  const cm  = Math.max(0, Math.floor(Number(childMat)   || 0));
  const cn  = Math.max(0, Math.floor(Number(childNoMat) || 0));
  return { extra_adults: Math.max(0, a - cap), num_guests: a + cm + cn };
}

// Room label for a booking row (Option A, 19 Jun 2026). A FLOATING booking
// (room_locked = 0) holds a room TYPE, not a specific room — the exact room is
// only firm once it's locked (at check-in, or when staff explicitly pin it).
// So a floating reservation reads as "Unassigned" (with its category, so staff
// know what to assign) rather than surfacing the auto-assigned room number,
// which made it look like a specific room was already blocked. Locked /
// checked-in bookings show their concrete room as before.
function isFloatingBooking(b: any): boolean {
  // room_locked = 0 → floating (room TYPE held, specific room not yet firm).
  // Defaults to locked when the field is absent so any row that doesn't carry
  // room_locked degrades to showing its room (no behaviour change).
  return Number(b?.room_locked ?? 1) === 0;
}
function bookingRoomLabel(b: any): string {
  if (isFloatingBooking(b)) {
    const cat = b?.room_category || b?.type_name || b?.room_type_name;
    return cat ? `Unassigned · ${cat}` : 'Unassigned';
  }
  return b?.room_name || b?.room_id || '—';
}

