// BrandAnnouncementBanner (Phase B2) — renders active brand-level
// announcements at the top of every location's dashboard. Per-user
// dismissal is stored in localStorage so the same user doesn't see the
// banner repeatedly after they've dismissed it. The brand admin can
// globally dismiss via the brand-admin dashboard.
function BrandAnnouncementBanner({ restaurantId, token }: { restaurantId: string; token: string }) {
  const [announcements, setAnnouncements] = useState<any[]>([]);
  const [dismissed, setDismissed] = useState<Set<string>>(() => {
    try {
      const stored = localStorage.getItem('brand_announcements_dismissed') || '[]';
      return new Set(JSON.parse(stored));
    } catch { return new Set(); }
  });

  useEffect(() => {
    fetch(`/api/restaurant/${restaurantId}/brand-announcements`,
      { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.ok ? r.json() : [])
      .then(setAnnouncements)
      .catch(() => {});
  }, [restaurantId, token]);

  const dismiss = (id: string) => {
    setDismissed(prev => {
      const next = new Set(prev); next.add(id);
      try {
        localStorage.setItem('brand_announcements_dismissed', JSON.stringify(Array.from(next)));
      } catch {}
      return next;
    });
  };

  const visible = announcements.filter(a => !dismissed.has(a.id));
  if (visible.length === 0) return null;

  return (
    <div className="max-w-[1700px] mx-auto px-3 sm:px-4 md:px-6 xl:px-8 pt-3 space-y-2">
      {visible.map(a => {
        const palette = a.level === 'URGENT'
          ? { bg: 'bg-red-50', border: 'border-red-300', text: 'text-red-900', icon: '🚨' }
          : a.level === 'WARNING'
          ? { bg: 'bg-amber-50', border: 'border-amber-300', text: 'text-amber-900', icon: '⚠' }
          : { bg: 'bg-sky-50', border: 'border-sky-300', text: 'text-sky-900', icon: '📢' };
        return (
          <div key={a.id} className={cn(palette.bg, palette.border, palette.text, "border rounded-2xl px-4 py-3 flex items-start gap-3 shadow-sm")}>
            <span className="text-xl shrink-0">{palette.icon}</span>
            <div className="flex-1 min-w-0">
              <p className="font-bold text-sm">{a.title}</p>
              {a.body && <p className="text-xs mt-0.5 leading-relaxed whitespace-pre-wrap">{a.body}</p>}
              <p className="text-[10px] mt-1 opacity-70">
                Brand announcement · {new Date(a.created_at).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })}
              </p>
            </div>
            <button
              onClick={() => dismiss(a.id)}
              title="Dismiss"
              className="shrink-0 p-1 hover:bg-white/40 rounded-full opacity-70 hover:opacity-100"
              aria-label="Dismiss announcement"
            >
              <X size={16} />
            </button>
          </div>
        );
      })}
    </div>
  );
}

function BillingNotice({ restaurantId, token }: { restaurantId: string; token: string }) {
  const [status, setStatus] = React.useState<any>(null);
  const [bannerDismissedUntil, setBannerDismissedUntil] = React.useState<number>(() => {
    try { return Number(localStorage.getItem(`billing_banner_dismissed_${restaurantId}`) || 0); } catch { return 0; }
  });

  const fetchStatus = React.useCallback(async () => {
    try {
      const res = await fetch(`/api/restaurant/${restaurantId}/billing-status`, {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      if (res.ok) {
        const data = await res.json();
        setStatus(data);
      }
    } catch (err) {
      console.warn('Billing status fetch failed:', err);
    }
  }, [restaurantId, token]);

  React.useEffect(() => {
    fetchStatus();
    // Hourly poll. 60 × 60 × 1000 = 3,600,000 ms.
    const id = setInterval(fetchStatus, 60 * 60 * 1000);
    return () => clearInterval(id);
  }, [fetchStatus]);

  // Sync the global read-only flag + body class. The fetch interceptor
  // and CSS grayout rule key off this.
  // read_only is TRUE when EITHER:
  //   (a) access_revoked = 1            → admin manually revoked
  //   (b) past due date + grace period  → automatic (server-enforced)
  // We fall back to access_revoked for older API responses.
  React.useEffect(() => {
    const isReadOnly = !!(status?.read_only ?? status?.access_revoked);
    (window as any).__atithiReadOnly = isReadOnly;
    if (isReadOnly) {
      document.body.classList.add('atithi-read-only');
    } else {
      document.body.classList.remove('atithi-read-only');
    }
    return () => {
      // Don't clear here — banner persists across re-renders; the flag
      // only flips when the status changes.
    };
  }, [status?.read_only, status?.access_revoked]);

  if (!status) return null;

  // Tenant deactivated — full-screen hard lock. The admin has paused the
  // entire restaurant. No read, no write, no escape. Owner can only sign
  // out and contact billing. Messaging matches the due-date expiry copy
  // (same voice, same contact paths, same "your data is safe" reassurance).
  if (status.tenant_inactive || status.is_active === false) {
    return (
      <div className="fixed inset-0 z-[9999] bg-[#1a1208]/95 backdrop-blur-sm flex items-center justify-center p-4">
        <div className="bg-white rounded-[28px] shadow-2xl max-w-xl w-full p-8 md:p-10 text-center">
          <div className="w-16 h-16 mx-auto rounded-full bg-red-100 flex items-center justify-center mb-5">
            <Clock size={32} className="text-red-600" />
          </div>
          <h1 className="text-2xl md:text-3xl font-bold font-serif mb-3 text-[#1a1208]">
            Service inactive
          </h1>
          <p className="text-[#6b5d52] mb-2">
            Your account access has been paused while we process your subscription.
          </p>
          <p className="text-sm text-[#9c8e85] mb-6">
            <strong className="text-emerald-700">Your data is safe</strong> and will be restored the moment your account is reactivated. All menus, orders, customer records, and reports are preserved.
          </p>
          <div className="bg-emerald-50 border border-emerald-200 rounded-2xl p-5 mb-6 text-left">
            <div className="text-[10px] font-bold uppercase tracking-widest text-emerald-700 mb-2">To restore service</div>
            <div className="text-sm text-[#1a1208] space-y-1.5">
              <div>📧 <strong>{status.billing_contact?.email || 'billing@atithi-setu.com'}</strong></div>
              <div>💬 WhatsApp <strong>{status.billing_contact?.whatsapp || '+91 70111 89371'}</strong></div>
              <div className="text-xs text-[#6b5d52] mt-2 italic">We typically respond within 2 hours during IST business hours.</div>
            </div>
          </div>
          <div className="flex gap-2">
            <a
              href={`https://wa.me/917011189371?text=${encodeURIComponent(`Hi, I need to restore service for my Atithi-Setu account: ${status.tenant_name || 'restaurant'}`)}`}
              target="_blank" rel="noopener noreferrer"
              data-allow-readonly
              className="flex-1 bg-red-600 hover:bg-red-700 text-white py-3 rounded-2xl font-bold transition-colors text-center"
            >
              Contact billing
            </a>
            <button
              type="button"
              onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
                try { localStorage.clear(); } catch {}
                try { sessionStorage.clear(); } catch {}
                // Remove the overlay toast if it's still present so the
                // reload doesn't have anything to fight against
                try {
                  const t = document.getElementById('atithi-tenant-inactive-overlay');
                  if (t) t.remove();
                } catch {}
                setTimeout(() => { window.location.reload(); }, 0);
              }}
              data-allow-readonly
              className="flex-1 bg-[#1a1208] hover:bg-[#3d3128] text-white py-3 rounded-2xl font-bold transition-colors"
            >
              Sign out
            </button>
          </div>
          <p className="text-xs text-[#9c8e85] mt-3">
            {status.tenant_name && <>Account: <strong>{status.tenant_name}</strong></>}
          </p>
        </div>
      </div>
    );
  }

  // Read-only mode — write access is blocked. Two independent triggers,
  // both surfaced with the same persistent red banner:
  //   (a) access_revoked = 1            → admin manually revoked
  //   (b) past due date + grace period  → automatic (server-enforced)
  // Owner can still view/export/download; mutations 402 server-side.
  // (status.read_only falls back to access_revoked for older API responses.)
  if (status.read_only ?? status.access_revoked) {
    const roReason = status.read_only_reason || status.access_revoked_reason
      || 'Subscription payment overdue';
    return (
      <div className="bg-gradient-to-r from-red-50 via-red-50 to-amber-50 border-b-2 border-red-300 shadow-sm">
        <div className="max-w-[1700px] mx-auto px-3 sm:px-4 md:px-6 xl:px-8 py-3">
          <div className="flex flex-col md:flex-row md:items-center gap-3">
            <div className="shrink-0 w-10 h-10 rounded-full bg-red-100 flex items-center justify-center">
              <Clock size={20} className="text-red-700" />
            </div>
            <div className="flex-1 min-w-0">
              <div className="font-bold text-red-900 text-sm md:text-base flex items-center gap-2 flex-wrap">
                <span>Read-only mode</span>
                <span className="px-2 py-0.5 rounded-full bg-red-200 text-red-800 text-[10px] font-bold uppercase tracking-wider">Subscription past due</span>
              </div>
              <div className="text-xs md:text-sm text-red-900/90 mt-0.5">
                Your account is in read-only mode while we process your subscription payment.
                You can <strong>view, export and download</strong> all data, but creating, editing and deleting — including new bills and invoices — are paused.
                <strong className="text-emerald-700"> Your data is safe.</strong> Restore service by contacting <strong>billing@atithi-setu.com</strong> or WhatsApp <strong>+91 70111 89371</strong>.
                {roReason && (
                  <span className="block mt-1 italic text-red-700/80">Reason: {roReason}</span>
                )}
              </div>
            </div>
            <div className="flex gap-2 shrink-0">
              <a
                href={`https://wa.me/917011189371?text=${encodeURIComponent(`Hi, I need to restore service for my Atithi-Setu account: ${status.tenant_name || restaurantId}`)}`}
                target="_blank" rel="noopener noreferrer"
                className="px-4 py-2 rounded-xl text-xs font-bold bg-red-600 text-white hover:bg-red-700 transition-colors whitespace-nowrap"
              >
                Restore service
              </a>
              <a
                href="mailto:billing@atithi-setu.com?subject=Restore%20service%20—%20Atithi-Setu%20account"
                className="px-4 py-2 rounded-xl text-xs font-bold bg-red-100 text-red-800 hover:bg-red-200 transition-colors whitespace-nowrap"
              >
                Email billing
              </a>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // Soft amber banner — past due but STILL WITHIN the grace period
  // (account is fully functional, this is just an early warning).
  // OVERDUE_PAST_GRACE is no longer handled here — once grace ends the
  // account flips to the read-only banner above, server-enforced.
  const isPastDue = status.billing_status === 'OVERDUE_GRACE';

  if (!isPastDue) return null;

  // Banner can be dismissed for the hour. localStorage stores the
  // timestamp until which it should stay hidden.
  const now = Date.now();
  if (bannerDismissedUntil > now) return null;

  // Within grace period — the account is still fully functional. This is
  // an early-warning amber banner. (Past-grace = read-only, handled above.)
  const daysPast = Math.abs(status.days_until_due || 0);
  const grace = Number(status.grace_period_days || 7);
  const daysUntilReadOnly = Math.max(0, grace - daysPast);
  const dueDate = status.subscription_due_date
    ? new Date(status.subscription_due_date).toLocaleDateString('en-IN', { day: 'numeric', month: 'short', year: 'numeric' })
    : 'a recent date';

  const dismissForOneHour = () => {
    const until = Date.now() + 60 * 60 * 1000;
    setBannerDismissedUntil(until);
    try { localStorage.setItem(`billing_banner_dismissed_${restaurantId}`, String(until)); } catch {}
  };

  return (
    <div className="border-b shadow-sm bg-amber-50 border-amber-200">
      <div className="max-w-[1700px] mx-auto px-3 sm:px-4 md:px-6 xl:px-8 py-3">
        <div className="flex flex-col md:flex-row md:items-center gap-3">
          <div className="shrink-0 w-9 h-9 rounded-full flex items-center justify-center bg-amber-100">
            <Clock size={18} className="text-amber-700" />
          </div>
          <div className="flex-1 min-w-0">
            <div className="font-bold text-amber-900 text-sm md:text-base">
              Subscription payment is past due
            </div>
            <div className="text-xs md:text-sm text-amber-800 mt-0.5">
              Payment was due on <strong>{dueDate}</strong>. Your account stays fully active for{' '}
              <strong>{daysUntilReadOnly} more {daysUntilReadOnly === 1 ? 'day' : 'days'}</strong> — after that it moves to
              read-only mode (you'll still be able to view and export, but new bills and edits will be paused).
              Complete payment or reach us at <strong>billing@atithi-setu.com</strong> / WhatsApp <strong>+91 70111 89371</strong>.
            </div>
          </div>
          <div className="flex gap-2 shrink-0">
            <a
              href={`https://wa.me/917011189371?text=${encodeURIComponent(`Hi, I need help with my Atithi-Setu subscription. Account: ${status.tenant_name || restaurantId}`)}`}
              target="_blank" rel="noopener noreferrer"
              className="px-4 py-1.5 rounded-xl text-xs font-bold transition-colors bg-amber-600 text-white hover:bg-amber-700"
            >
              Contact billing
            </a>
            <button
              onClick={dismissForOneHour}
              className="px-3 py-1.5 rounded-xl text-xs font-bold transition-colors bg-amber-100 text-amber-800 hover:bg-amber-200"
              title="Hide for 1 hour. Will reappear automatically until resolved."
            >
              Remind me later
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

