  const [viewFolio, setViewFolio] = useState<any>(null);
  // Sprint RS — F&B charge modal state (phone-in room service, minibar, banquet)
  const [fnbChargeFolio, setFnbChargeFolio] = useState<any>(null);
  // RS-FIX — unbilled room-service orders (folio_post_status='PENDING_MANUAL')
  // awaiting front-desk reconciliation onto a folio.
  const [pendingFolioOrders, setPendingFolioOrders] = useState<any[]>([]);
  // Phase 4
  const [hotelFaqs, setHotelFaqs] = useState<any[]>([]);
  const [editingFaq, setEditingFaq] = useState<any>(null);
  const [showFaqModal, setShowFaqModal] = useState(false);
  // Derived flag used to conditionally show hotel tabs + UI
  const isHotelEnabled = !!restaurant && (
    (restaurant as any).property_type === 'HOTEL' ||
    (restaurant as any).property_type === 'BOTH'
  );
  const isRestaurantEnabled = !!restaurant && (
    !(restaurant as any).property_type ||
    (restaurant as any).property_type === 'RESTAURANT' ||
    (restaurant as any).property_type === 'BOTH'
  );
  // ── Dashboard mode ─────────────────────────────────────────────────────
  // For BOTH-mode tenants (Restaurant + Hotel on the same tenant), the
  // owner can pick which "side" of the business to see in the nav. The
  // toggle UI is hidden for restaurant-only / hotel-only tenants since
  // there's nothing to switch — bothEnabled gates everything.
  //
  // Persisted per-tenant so a multi-location owner who switches outlets
  // gets that outlet's last-used mode back. Default = RESTAURANT because
  // most tenants start as restaurant-only and add hotel later.
  const bothEnabled = isRestaurantEnabled && isHotelEnabled;
  const [dashboardMode, setDashboardMode] = useState<'RESTAURANT' | 'HOTEL'>(() => {
    try {
      const k = `atithi_dashboard_mode_${restaurantId}`;
      const v = typeof window !== 'undefined' ? localStorage.getItem(k) : null;
      if (v === 'HOTEL' || v === 'RESTAURANT') return v;
    } catch { /* ignore */ }
    return 'RESTAURANT';
  });
  useEffect(() => {
    try {
      if (typeof window !== 'undefined') {
        localStorage.setItem(`atithi_dashboard_mode_${restaurantId}`, dashboardMode);
      }
    } catch { /* ignore quota / private-mode failures */ }
  }, [dashboardMode, restaurantId]);
  // If the tenant only has one side enabled, force the mode to match so
  // any downstream rendering that checks dashboardMode doesn't surprise
  // the user (e.g. a freshly-disabled-by-admin hotel module shouldn't
  // leave the owner stuck on a now-empty Hotel view).
  useEffect(() => {
    if (!bothEnabled) {
      const forced: 'RESTAURANT' | 'HOTEL' = isHotelEnabled ? 'HOTEL' : 'RESTAURANT';
      setDashboardMode(prev => prev === forced ? prev : forced);
    }
  }, [bothEnabled, isHotelEnabled]);

  // Resolves the EFFECTIVE Command & Control view per the active mode:
  //   • restaurant-only tenant → false (restaurant Monitor)
  //   • hotel-only tenant      → true  (hotel Monitor)
  //   • BOTH-mode tenant       → tracks the dashboardMode toggle
  // The MONITOR tab uses this to swap the entire Command Center content
  // so a hotel-mode owner isn't staring at restaurant tables and KDS.
  const isHotelView = isHotelEnabled && (
    !isRestaurantEnabled || (bothEnabled && dashboardMode === 'HOTEL')
  );

  // ── Mode-switch safety net ─────────────────────────────────────────────
  // If the owner is on (say) ROOMS and flips to Restaurant mode, the ROOMS
  // tab disappears. Auto-redirect to Command & Control so they don't end
  // up on an empty view. The two sets are defined again inside the nav
  // IIFE for the visibility check; keeping them in sync is enforced by
  // the fact that both lists touch every tab id at most twice. If we ever
  // add a tab, missing it here would mean the auto-redirect doesn't fire
  // — a benign UI bug, not a crash.
  useEffect(() => {
    if (!bothEnabled) return;
    const restaurantOnlyIds = new Set(['MENU', 'INVENTORY', 'DELIVERY', 'QR', 'BOOKINGS', 'ORDERS']);
    const hotelOnlyIds      = new Set(['ROOMS', 'ROOM_SETUP', 'HOTEL_BOOKINGS', 'SERVICES', 'SERVICE_REQUESTS', 'FOLIOS', 'COMPLIANCE', 'CONCIERGE_FAQ']);
    const hidden =
      (dashboardMode === 'RESTAURANT' && hotelOnlyIds.has(activeTab)) ||
      (dashboardMode === 'HOTEL'      && restaurantOnlyIds.has(activeTab));
    if (hidden) setActiveTab('MONITOR');
    // activeTab intentionally not in deps — we only want to redirect at
    // the moment the mode flips, not every time the user clicks a tab.
    // (Owner-only STAFF_ACCESS gate lives in its own effect below.)
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [dashboardMode, bothEnabled]);

  // Alerts toggle (default TRUE unless explicitly disabled in Settings)
  const alertsEnabled = !restaurant || ((restaurant as any).alerts_enabled !== 0 && (restaurant as any).alerts_enabled !== false);
  const [staff, setStaff] = useState<any[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [feedback, setFeedback] = useState<any[]>([]);
  const [loadingFeedback, setLoadingFeedback] = useState(false);
  const [loadingOrders, setLoadingOrders] = useState(false);
  const [liveTables, setLiveTables] = useState<LiveTableView[]>([]);
  const [liveLoading, setLiveLoading] = useState(false);
  const [liveLastRefresh, setLiveLastRefresh] = useState<Date | null>(null);
  const [liveNow, setLiveNow] = useState(Date.now());
  const [liveOrders, setLiveOrders] = useState<Order[]>([]);
  const [liveOrdersExpanded, setLiveOrdersExpanded] = useState(true);
  // S3 (17 Jun 2026): staff "Modify order" — the live order being edited (items/qty).
  const [editOrder, setEditOrder] = useState<any | null>(null);
  // Cloud-kitchen: dedicated panel state, fetched alongside /tables/live
  const [cloudKitchenOrders, setCloudKitchenOrders] = useState<any[]>([]);
  const [cloudKitchenSummary, setCloudKitchenSummary] = useState<{
    total_active: number; pending: number; awaiting_dispatch: number;
    breached: number; total_revenue: number; sla_minutes: number;
  } | null>(null);
  const [viewBillTable, setViewBillTable] = useState<{ id: string; name: string } | null>(null);
  const [waiterCalls, setWaiterCalls] = useState<any[]>([]);

  // ── Inventory Module — Phase 1+2 state ───────────────────────────────────
  const [inventoryIngredients, setInventoryIngredients] = useState<any[]>([]);
  const [inventorySuppliers, setInventorySuppliers] = useState<any[]>([]);
  const [inventoryPOs, setInventoryPOs] = useState<any[]>([]);
  const [inventoryGRNs, setInventoryGRNs] = useState<any[]>([]);
  const [inventoryLoading, setInventoryLoading] = useState(false);
  // Modal/edit state per sub-tab
  const [editingIngredient, setEditingIngredient] = useState<any | null>(null);  // null = closed; {} = creating; {id...} = editing existing
  const [adjustingStock, setAdjustingStock] = useState<any | null>(null);
  const [editingSupplier, setEditingSupplier] = useState<any | null>(null);
  const [poFilter, setPOFilter] = useState<'ALL' | 'DRAFT' | 'SENT' | 'PARTIAL' | 'RECEIVED' | 'CANCELLED'>('ALL');
  const [creatingPO, setCreatingPO] = useState(false);
  // Smart PO multi-supplier preview (Wave 2)
  const [smartPoPreview, setSmartPoPreview] = useState<any[] | null>(null);
  const [smartPoSubmitting, setSmartPoSubmitting] = useState(false);
  const [viewingPO, setViewingPO] = useState<any | null>(null);
  const [creatingGRN, setCreatingGRN] = useState<{ poId?: string } | null>(null);
  const [viewingGRN, setViewingGRN] = useState<any | null>(null);
  // Phase 3 — wastage + physical counts
  const [inventoryWastage, setInventoryWastage] = useState<any[]>([]);
  const [inventoryCounts, setInventoryCounts] = useState<any[]>([]);
  const [loggingWastage, setLoggingWastage] = useState(false);
  const [viewingCount, setViewingCount] = useState<any | null>(null);
  const [startingCount, setStartingCount] = useState(false);
  // Recipe builder modal — opened from Menu Management for a specific menu item
  const [recipeBuilderItem, setRecipeBuilderItem] = useState<any | null>(null);
  // CSV import preview state — shared modal for Ingredients + Suppliers
  const [invCsvImport, setInvCsvImport] = useState<{
    entity: 'ingredients' | 'suppliers';
    rows: any[];   // each row has _selected + _isDuplicate flags
    importing: boolean;
  } | null>(null);
  // Phase 4: forecasting dashboard
  const [inventoryDashboard, setInventoryDashboard] = useState<any | null>(null);
  const [forecastHorizon, setForecastHorizon] = useState<'daily' | 'weekly' | 'monthly'>('daily');
  // Onboarding wizard — shown on empty inventory or via manual launch
  const [showOnboarding, setShowOnboarding] = useState(false);
  // Ingredients table filter + sort state
  const [ingFilter, setIngFilter] = useState<{
    search: string;
    category: string;
    type: 'ALL' | 'RAW' | 'PACKAGED';
    status: 'ALL' | 'LOW' | 'OUT' | 'IN_STOCK' | 'DUPLICATES';
  }>({ search: '', category: 'ALL', type: 'ALL', status: 'ALL' });
  const [ingSort, setIngSort] = useState<{ key: string; dir: 'asc' | 'desc' }>({ key: 'name', dir: 'asc' });
  // Suppliers card-grid search
  const [supSearch, setSupSearch] = useState('');
  // PO + GRN + Wastage + Counts table filter/sort state. Date filters use ISO yyyy-mm-dd strings.
  const [poSearch, setPOSearch] = useState('');
  const [poDateFrom, setPODateFrom] = useState('');
  const [poDateTo, setPODateTo] = useState('');
  const [poSort, setPOSort] = useState<{ key: string; dir: 'asc' | 'desc' }>({ key: 'raised_at', dir: 'desc' });
  const [grnSearch, setGRNSearch] = useState('');
  const [grnDateFrom, setGRNDateFrom] = useState('');
  const [grnDateTo, setGRNDateTo] = useState('');
  const [grnSort, setGRNSort] = useState<{ key: string; dir: 'asc' | 'desc' }>({ key: 'received_at', dir: 'desc' });
  const [wastageSearch, setWastageSearch] = useState('');
  const [wastageReason, setWastageReason] = useState<'ALL' | 'SPOILAGE' | 'BURN' | 'DROPPED' | 'EXPIRY' | 'OTHER'>('ALL');
  const [wastageDateFrom, setWastageDateFrom] = useState('');
  const [wastageDateTo, setWastageDateTo] = useState('');
  const [wastageSort, setWastageSort] = useState<{ key: string; dir: 'asc' | 'desc' }>({ key: 'logged_at', dir: 'desc' });
  const [countSearch, setCountSearch] = useState('');
  const [countStatusFilter, setCountStatusFilter] = useState<'ALL' | 'IN_PROGRESS' | 'COMPLETED'>('ALL');
  const [countSort, setCountSort] = useState<{ key: string; dir: 'asc' | 'desc' }>({ key: 'count_date', dir: 'desc' });

  // ── Audible + visual alerts for unacknowledged items (Phase 6) ────────────
  // Owner/Manager hears a chime every 4s and sees pulsing cards when:
  //   - any table has session_status === 'bill_requested'   (customer called for bill)
  //   - any service request is PENDING (hotel guest service ask)
  //   - any waiter call is 'pending' (restaurant customer pressed Call Waiter)
  // The chime stops the moment all three queues drop to zero.
  const pendingBillReqs     = liveTables.filter(t => t.session_status === 'bill_requested').length;
  const pendingServiceReqs  = hotelRequests.filter(r => r.status === 'PENDING').length;
  const pendingWaiterCalls  = waiterCalls.filter(c => c.status === 'pending').length;
  const totalPendingAlerts  = pendingBillReqs + pendingServiceReqs + pendingWaiterCalls;
  const alertLabel =
    pendingServiceReqs > 0 ? `${pendingServiceReqs} service request${pendingServiceReqs === 1 ? '' : 's'}`
    : pendingWaiterCalls > 0 ? `${pendingWaiterCalls} waiter call${pendingWaiterCalls === 1 ? '' : 's'}`
    : pendingBillReqs > 0 ? `${pendingBillReqs} bill request${pendingBillReqs === 1 ? '' : 's'}`
    : 'Alert';
  useAlertChime(alertsEnabled && totalPendingAlerts > 0, { label: alertLabel });

  // ── Monitor table controls ─────────────────────────────────────────────────
  const [monitorSearch,       setMonitorSearch]       = useState('');
  const [monitorStatusFilter, setMonitorStatusFilter] = useState<'ALL'|'AVAILABLE'|'OCCUPIED'|'NOT_AVAILABLE'|'BILL_REQUESTED'>('ALL');
  const [monitorSort,         setMonitorSort]         = useState<{ col: string; dir: 'asc'|'desc' }>({ col: 'status', dir: 'asc' });
  const [monitorColOpen,      setMonitorColOpen]      = useState(false);
  const monitorCols = useColumnConfig('monitor', MONITOR_COL_DEFAULTS);
  const [waiterCallsExpanded, setWaiterCallsExpanded] = useState(true);
  const [allWaiters, setAllWaiters] = useState<{ id: string; name: string }[]>([]);
  const [allChefs,   setAllChefs]   = useState<{ id: string; name: string }[]>([]);
  const [orderEtaEdits, setOrderEtaEdits] = useState<Record<string, string>>({});
  const [isAddingItem, setIsAddingItem] = useState(false);
  const [isAddingStaff, setIsAddingStaff] = useState(false);

  // ── Invoice Tab State ─────────────────────────────────────────────────────
  const [invoices, setInvoices]               = useState<any[]>([]);
  const [invoiceSearch, setInvoiceSearch]     = useState('');
  const [invoiceStatusFilter, setInvoiceStatusFilter] = useState<'ALL'|'UNPAID'|'PAID'|'PRINTED'>('ALL');
  const [invoiceSortKey, setInvoiceSortKey]   = useState<string>('date');
  const [invoiceSortDir, setInvoiceSortDir]   = useState<'asc'|'desc'>('desc');

  // ── Owner Profile (contact info) ──────────────────────────────────────────
  const [ownerProfile, setOwnerProfile] = useState<{ name: string; email: string; phone: string }>({ name: '', email: '', phone: '' });
  const [profileSaving, setProfileSaving] = useState(false);
  const [profileSaved, setProfileSaved] = useState(false);

  // ── Hotel Rules (Phase H1 — per-tenant business rules) ──────────────────
  // Fetched from /api/restaurant/:id/hotel/settings when the SETTINGS tab
  // is opened on a Hotel-enabled tenant. Used in two places:
  //   1. Settings UI — owner edits min/max stay, refund policy, late-checkout time
  //   2. Booking modal — shows a hint ("Minimum 2 nights") near the date fields
  const [hotelSettings, setHotelSettings] = useState<{
    min_stay_nights: number;
    max_stay_nights: number | null;
    refund_full_days: number | null;
    refund_partial_pct: number | null;
    late_checkout_time: string | null;
    // Phase H2 — hotel tax config
    gst_slab1_max: number;
    gst_slab1_rate: number;
    gst_slab2_max: number;
    gst_slab2_rate: number;
    gst_slab3_rate: number;
    service_charge_percent: number;
    // Req 1b — pre-check-in ID gate
    require_id_at_checkin: boolean;
  }>({
    min_stay_nights: 1, max_stay_nights: null,
    refund_full_days: null, refund_partial_pct: null, late_checkout_time: null,
    gst_slab1_max: 1000, gst_slab1_rate: 0,
    gst_slab2_max: 7500, gst_slab2_rate: 12,
    gst_slab3_rate: 18,
    service_charge_percent: 0,
    require_id_at_checkin: true,
  });

  // BCG Tariff Phase 2 — snapshot of the matrix tariff configuration.
  // Loaded lazily when the user opens Settings → Tariff Configuration
  // OR when a booking modal needs the meal-plan list. Empty by default
  // for LEGACY tenants — no network calls cost.
  const [tariffData, setTariffData] = useState<{
    tariff_model: 'LEGACY' | 'MATRIX';
    seasons: any[];
    season_periods: any[];
    meal_plans: any[];
    room_tariffs: any[];
    extra_person_charges: any[];
    room_types: any[];
  }>({
    // BCG Tariff Phase 4 (7 Jun 2026) — MATRIX is the default mode now.
    // Tenants can still flip to LEGACY via the toggle if they prefer the
    // simpler date-range overrides flow.
    tariff_model: 'MATRIX', seasons: [], season_periods: [],
    meal_plans: [], room_tariffs: [], extra_person_charges: [], room_types: [],
  });
  const [tariffLoading, setTariffLoading] = useState(false);
  const [tariffError, setTariffError] = useState<string | null>(null);
  const fetchTariff = useCallback(async () => {
    // BCG Tariff Phase 4.7 (8 Jun 2026) — client report: "meal plans
    // disappear between sessions; clicking Matrix toggle makes them
    // reappear." Root cause was the silent catch below + the effect
    // depending only on [activeTab, isHotelEnabled] (token / restaurantId
    // changes never re-triggered the fetch). Now we log failures, expose
    // the error to the UI, and the boot-time useEffect re-fires whenever
    // token or restaurantId changes.
    if (!restaurantId || !token) return; // no auth yet
    setTariffLoading(true);
    setTariffError(null);
    try {
      const data = await hotelApi('/tariff');
      setTariffData({
        tariff_model: data.tariff_model === 'LEGACY' ? 'LEGACY' : 'MATRIX',
        seasons: Array.isArray(data.seasons) ? data.seasons : [],
        season_periods: Array.isArray(data.season_periods) ? data.season_periods : [],
        meal_plans: Array.isArray(data.meal_plans) ? data.meal_plans : [],
        room_tariffs: Array.isArray(data.room_tariffs) ? data.room_tariffs : [],
        extra_person_charges: Array.isArray(data.extra_person_charges) ? data.extra_person_charges : [],
        room_types: Array.isArray(data.room_types) ? data.room_types : [],
      });
    } catch (err: any) {
      // Loud failure — was previously swallowed. Now visible in console
      // AND surfaced to the UI via tariffError so the owner sees
      // "couldn't load tariff" instead of a confusing empty state.
      console.error('[fetchTariff] failed:', err?.message || err);
      setTariffError(err?.message || 'Failed to load tariff configuration. Try refreshing.');
    }
    finally { setTariffLoading(false); }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [restaurantId, token]);

  // BCG Tariff Phase 4.7 — Dedicated boot-time fetch for tariff data.
  // Fires whenever auth (restaurantId + token) becomes available AND the
  // hotel module is enabled. Independent of activeTab so the data is
  // ready by the time the owner opens the Settings or Hotel Bookings tab.
  useEffect(() => {
    if (!isHotelEnabled || !restaurantId || !token) return;
    fetchTariff();
  }, [isHotelEnabled, restaurantId, token, fetchTariff]);

  // ════════════════════════════════════════════════════════════════════
  // BCG Tariff Phase 4.2 — Client-side matrix price PREVIEW.
  //
  // Mirrors the server's computeBookingTotalWithExtras so the booking
  // and walk-in modals can show staff exactly what the server WILL
  // invoice — live, as they pick rooms, meal plans, and extras. The
  // backend is still the source of truth; this preview just answers the
  // ground-truth question "what will my invoice look like?"
  //
  // Returns null when the tenant isn't in MATRIX mode or when the
  // matrix lacks the needed cells (the form's existing Rate-per-night
  // field is the source of truth in those cases).
  // ════════════════════════════════════════════════════════════════════
  const previewMatrixPrice = useCallback((opts: {
    room_id: string;
    check_in_date: string;
    check_out_date: string;
    booking_type?: string;
    meal_plan_id?: string | null;
    extra_adults?: number;
    extra_children_with_mattress?: number;
    extra_children_no_mattress?: number;
  }): {
    per_night: Array<{ date: string; base_rate: number; extras: number; season_id: string | null; source: string }>;
    extra_lines: Array<{ type: string; label: string; count: number; total: number }>;
    base_total: number;
    extras_total: number;
    total: number;
    matrix_used: boolean;
  } | null => {
    if (tariffData.tariff_model !== 'MATRIX') return null;
    // No meal-plan guard: still preview the per-night BASE rate so staff see
    // pricing even with "None" selected. Extra-person charges resolve only
    // when a plan is chosen (they're keyed by meal-plan), but the extra-person
    // COUNTS are always itemised in extra_lines below.
    const room = hotelRooms.find(r => r.id === opts.room_id);
    if (!room?.type_id) return null;
    const ci = String(opts.check_in_date || '').slice(0, 10);
    const co = String(opts.check_out_date || '').slice(0, 10);
    if (!ci || !co) return null;

    const dates: string[] = [];
    if ((opts.booking_type || 'OVERNIGHT').toUpperCase() === 'DAY_USE' || ci === co) {
      dates.push(ci);
    } else {
      let cursor = new Date(ci + 'T12:00:00Z');
      const end = new Date(co + 'T12:00:00Z');
      while (cursor < end) {
        dates.push(cursor.toISOString().slice(0, 10));
        cursor = new Date(cursor.getTime() + 86400000);
      }
    }

    // SEASON-FIX (15 Jun 2026) — mirror the server's getSeasonForDate EXACTLY:
    // when several active periods cover the date, the MOST SPECIFIC (narrowest
    // date span) wins, so a specific PEAK window overrides a broad OFF /
    // year-long catch-all. display_order is only a tiebreak between equal
    // spans. Previously this preview ranked purely by display_order, so it
    // could disagree with what the folio actually bills (e.g. show OFF at
    // booking time but charge PEAK at check-in) — exactly the "check-in is
    // picking peak-season rate" mismatch reported. Now preview == billing.
    const seasonForDate = (d: string): string | null => {
      const matches = (tariffData.season_periods || []).filter((p: any) => {
        const s = String(p.start_date || '').slice(0, 10);
        const e = String(p.end_date || '').slice(0, 10);
        return d >= s && d <= e;
      });
      if (!matches.length) return null;
      if (matches.length === 1) return matches[0].season_id || null;
      const spanDays = (p: any): number => {
        const s = Date.parse(`${String(p.start_date).slice(0, 10)}T00:00:00Z`);
        const e = Date.parse(`${String(p.end_date).slice(0, 10)}T00:00:00Z`);
        return (Number.isFinite(s) && Number.isFinite(e) && e >= s) ? (e - s) : Number.MAX_SAFE_INTEGER;
      };
      const ordered = matches
        .map((p: any) => ({
          id: p.season_id,
          span: spanDays(p),
          order: (tariffData.seasons.find((s: any) => s.id === p.season_id)?.display_order) ?? 99,
        }))
        .sort((a: any, b: any) => (a.span !== b.span ? a.span - b.span : a.order - b.order));
      return ordered[0]?.id || null;
    };

    const extras = {
      ADULT:               Math.max(0, Number(opts.extra_adults || 0)),
      CHILD_WITH_MATTRESS: Math.max(0, Number(opts.extra_children_with_mattress || 0)),
      CHILD_NO_MATTRESS:   Math.max(0, Number(opts.extra_children_no_mattress || 0)),
    };
    const perNight: Array<{ date: string; base_rate: number; extras: number; season_id: string | null; source: string }> = [];
    const extraTotalsByType: Record<string, number> = {};
    let anyMatrix = false;
    for (const d of dates) {
      const seasonId = seasonForDate(d);
      let baseRate = 0;
      let source = 'BASE_RATE';
      if (seasonId) {
        // Room-level override beats type default.
        const roomOverride = (tariffData.room_tariffs || []).find((r: any) =>
          r.room_type_id === room.type_id && r.season_id === seasonId
          && r.meal_plan_id === opts.meal_plan_id && r.room_id_override === room.id
        );
        if (roomOverride && roomOverride.rate != null) {
          baseRate = Number(roomOverride.rate);
          source = 'MATRIX_ROOM';
          anyMatrix = true;
        } else {
          const typeRow = (tariffData.room_tariffs || []).find((r: any) =>
            r.room_type_id === room.type_id && r.season_id === seasonId
            && r.meal_plan_id === opts.meal_plan_id && !r.room_id_override
          );
          if (typeRow && typeRow.rate != null) {
            baseRate = Number(typeRow.rate);
            source = 'MATRIX_TYPE';
            anyMatrix = true;
          }
        }
      }
      // Per-cell fallback to room.base_rate when matrix has no entry.
      if (baseRate === 0) {
        baseRate = Number(room.base_rate || 0);
        source = 'BASE_RATE_FALLBACK';
      }
      let extrasForNight = 0;
      if (seasonId) {
        for (const [pt, count] of Object.entries(extras)) {
          if (count > 0) {
            // Per-person charge. With a meal plan → exact (type, season, plan)
            // row. Room-only (no meal plan) → LOWEST configured rate for this
            // type + season, mirroring the server's getExtraPersonChargeForDate
            // so the preview matches the folio (19 Jun 2026).
            let per = 0;
            if (opts.meal_plan_id) {
              const row = (tariffData.extra_person_charges || []).find((r: any) =>
                r.person_type === pt && r.season_id === seasonId && r.meal_plan_id === opts.meal_plan_id
              );
              per = row ? Number(row.charge || 0) : 0;
            } else {
              const rows = (tariffData.extra_person_charges || []).filter((r: any) =>
                r.person_type === pt && r.season_id === seasonId && Number(r.charge || 0) > 0
              );
              per = rows.length ? Math.min(...rows.map((r: any) => Number(r.charge || 0))) : 0;
            }
            if (per > 0) {
              const add = per * count;
              extrasForNight += add;
              extraTotalsByType[pt] = (extraTotalsByType[pt] || 0) + add;
              anyMatrix = true;
            }
          }
        }
      }
      perNight.push({ date: d, base_rate: baseRate, extras: extrasForNight, season_id: seasonId, source });
    }
    const baseTotal   = Math.round(perNight.reduce((s, n) => s + n.base_rate, 0) * 100) / 100;
    const extrasTotal = Math.round(perNight.reduce((s, n) => s + n.extras,    0) * 100) / 100;
    // Itemise the extra persons so the live preview can show each added
    // adult / child line (count + ₹), even when the per-person charge is
    // ₹0 because it isn't configured yet for this season / meal-plan.
    const PT_LABELS: Record<string, string> = {
      ADULT: 'Extra adult',
      CHILD_WITH_MATTRESS: 'Extra child (mattress)',
      CHILD_NO_MATTRESS: 'Extra child (no mattress)',
    };
    const extra_lines = (Object.entries(extras) as [string, number][])
      .filter(([, c]) => c > 0)
      .map(([pt, c]) => ({ type: pt, label: PT_LABELS[pt] || pt, count: c, total: Math.round((extraTotalsByType[pt] || 0) * 100) / 100 }));
    return {
      per_night: perNight,
      extra_lines,
      base_total: baseTotal,
      extras_total: extrasTotal,
      total: Math.round((baseTotal + extrasTotal) * 100) / 100,
      matrix_used: anyMatrix,
    };
  }, [tariffData, hotelRooms]);

