  // ── Menu Management Enhancements ─────────────────────────────────────────────
  const [menuCatFilter, setMenuCatFilter] = useState<string>('ALL');
  const [menuSearchTerm, setMenuSearchTerm] = useState<string>('');
  const [menuViewMode, setMenuViewMode] = useState<'grid' | 'grouped'>('grouped');
  const [csvPreviewRows, setCsvPreviewRows] = useState<any[] | null>(null);
  const [csvImporting, setCsvImporting] = useState(false);
  const [generatingImageId, setGeneratingImageId] = useState<string | null>(null);
  const [newItemCategoryCustom, setNewItemCategoryCustom] = useState<string>('');

  // Role-Based Tab Access Control
  const [allowedTabs, setAllowedTabs] = useState<string[] | null>(null); // null = no restriction

  // STAFF_ACCESS owner-only gate (founder request 7 Jun 2026 — critical).
  // The /role-permissions endpoint already 403s on writes from non-owners,
  // but the tab itself was visible to non-owners with ancient/legacy
  // permission lists (via ALWAYS_VISIBLE_TABS grandfathering). We now read
  // the role from localStorage and use isOwnerOrAdmin to:
  //   • filter STAFF_ACCESS out of the GENERAL lane nav array
  //   • short-circuit the STAFF_ACCESS content branch with Access Denied
  //   • auto-redirect to MONITOR if a non-owner somehow lands on STAFF_ACCESS
  //
  // Reading once (not as state) is fine — the role only changes on
  // logout/login, and the app reloads at that point. SUPER_ADMIN and CTO
  // are platform roles that already see everything; OWNER is the tenant's
  // top role. Everyone else (MANAGER / CASHIER / FRONT_DESK / CHEF /
  // WAITER / HOUSEKEEPING / MAINTENANCE / CONCIERGE) is denied.
  const currentRole: string = (typeof window !== 'undefined'
    ? (localStorage.getItem('role') || '')
    : '');
  const isOwnerOrAdmin: boolean = currentRole === 'OWNER'
                                || currentRole === 'SUPER_ADMIN'
                                || currentRole === 'CTO';
  // Owner-only redirect: if a non-owner directly types ?tab=STAFF_ACCESS
  // (or had it cached from a prior owner session in localStorage), bounce
  // them to MONITOR. UI also hides the nav entry, so this only fires on
  // the URL/cache edge cases.
  useEffect(() => {
    if (activeTab === 'STAFF_ACCESS' && !isOwnerOrAdmin) {
      setActiveTab('MONITOR');
    }
    // Room Setup is owner-only too — bounce non-owners who reach it via a
    // stale URL/cache (the nav already hides the entry for them).
    if (activeTab === 'ROOM_SETUP' && !isOwnerOrAdmin) {
      setActiveTab('MONITOR');
    }
  }, [activeTab, isOwnerOrAdmin]);

  const [showTemplatePanel, setShowTemplatePanel]     = useState(false);
  const [showOnDemandModal, setShowOnDemandModal]     = useState(false);
  const [printPreviewHtml, setPrintPreviewHtml]       = useState<string|null>(null);
  const [loadingInvoices, setLoadingInvoices]         = useState(false);
  const [invoiceTemplate, setInvoiceTemplate] = useState<{
    showGSTIN: boolean; showCity: boolean; showCustomerPhone: boolean;
    showPaymentMethod: boolean; showItemBreakdown: boolean; showDiscountLine: boolean;
    showThankYouNote: boolean; footerText: string;
  }>(() => {
    try { return JSON.parse(localStorage.getItem('as-invoice-tpl') || 'null') || {
      showGSTIN: true, showCity: true, showCustomerPhone: true,
      showPaymentMethod: true, showItemBreakdown: true, showDiscountLine: true,
      showThankYouNote: true, footerText: 'Thank you for your business!',
    }; } catch { return {
      showGSTIN: true, showCity: true, showCustomerPhone: true,
      showPaymentMethod: true, showItemBreakdown: true, showDiscountLine: true,
      showThankYouNote: true, footerText: 'Thank you for your business!',
    }; }
  });
  // On-demand invoice form state
  const [odInvoiceItems, setOdInvoiceItems]   = useState<{name:string;qty:number;price:number}[]>([{name:'',qty:1,price:0}]);
  const [odCustomer, setOdCustomer]           = useState({name:'',phone:'',reference:''});
  const [odDiscount, setOdDiscount]           = useState(0);
  const [odSvcPct, setOdSvcPct]               = useState(0);
  const [odGstPct, setOdGstPct]               = useState(0);
  const [odApplyGst, setOdApplyGst]           = useState(false);
  const [odSaving, setOdSaving]               = useState(false);
  // Surface backend / network errors so a failed "Generate Invoice"
  // click doesn't silently dismiss. Without this, a 500 / network drop
  // / auth expiry would just flip the loading spinner off with no UX.
  const [odSaveError, setOdSaveError]         = useState<string>('');
  const [odSearchActive, setOdSearchActive]   = useState<number | null>(null);
  // ── POS-style tile UI state for the on-demand invoice modal ────────────
  // The modal's UX shifted from "type item names in rows" to "tap menu
  // tiles like a POSist / Petpooja terminal." These three fields drive
  // the new layout; the data shape of odInvoiceItems / odCustomer etc.
  // is unchanged so the backend payload + preview-totals fetch + save
  // handler all continue to work as-is.
  const [odCategoryFilter, setOdCategoryFilter] = useState<string>('ALL');
  const [odTileSearch, setOdTileSearch]         = useState<string>('');
  const [showCustomItemForm, setShowCustomItemForm] = useState(false);
  const [customItemDraft, setCustomItemDraft]   = useState<{name:string;qty:number;price:number}>({name:'',qty:1,price:0});
  // Server-computed preview for the manual-invoice modal. The form fields
  // are still inputs; the totals (incl. multi-tax breakdown + auto-loyalty
  // discount) are computed by the same code path that will run when the
  // owner clicks "Generate Invoice". This keeps the live preview honest.
  const [odPreview, setOdPreview]             = useState<any | null>(null);
  const [odPreviewLoading, setOdPreviewLoading] = useState(false);

  // ── Tenant tax_config snapshot (shared by New Invoice + Edit Invoice) ──
  // Fetched ONCE per modal open via /api/restaurant/:id/tax-config. We use
  // this to decide the layout BEFORE any preview is computed — that way
  // an empty cart still shows "Auto-applied taxes: GST 5%, Service Tax 10%"
  // instead of misleading legacy "Service Charge %: 0" / "GST %: 5 OFF"
  // inputs. The preview is still used for the actual ₹ amounts when items
  // are present.
  const [activeTaxLines, setActiveTaxLines] = useState<Array<{ id: string; label: string; rate_percent: number }>>([]);
  // Phase H3 — tenant-level default service charge %. Pre-populates the
  // editable Service Charge field on every new invoice / postpaid
  // session. Server filters service-labeled tax_config rows so this
  // is the single source of truth.
  const [tenantServiceChargePct, setTenantServiceChargePct] = useState<number>(0);
  const fetchActiveTaxLines = async () => {
    try {
      const res = await fetch(`/api/restaurant/${restaurantId}/tax-config`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!res.ok) { setActiveTaxLines([]); setTenantServiceChargePct(0); return; }
      const data = await res.json();
      const lines = Array.isArray(data?.active_configs)
        ? data.active_configs
            .filter((l: any) => Number(l.enabled || 1) === 1 && Number(l.rate_percent || 0) > 0)
            .map((l: any) => ({
              id: String(l.id),
              label: String(l.label || l.id),
              rate_percent: Number(l.rate_percent || 0),
            }))
        : [];
      setActiveTaxLines(lines);
      setTenantServiceChargePct(Number(data?.service_charge_percent || 0));
    } catch {
      setActiveTaxLines([]);
      setTenantServiceChargePct(0);
    }
  };
  // Derived: true when Tax Lines from Settings drive the math. Replaces
  // the previous preview-based check so the layout is correct even with
  // an empty cart.
  const isTaxCfgDrivenTenant = activeTaxLines.length > 0;

  // Debounced fetch of the server-side preview whenever any input that
  // affects totals changes (items list, customer phone for loyalty lookup,
  // discount, service %, GST fallback). 300ms debounce keeps the network
  // chatter sane while typing.
  useEffect(() => {
    if (!showOnDemandModal || !restaurantId) return;
    const subtotalLocal = odInvoiceItems.reduce(
      (s, it) => s + Number(it.price || 0) * Number(it.qty || 1), 0
    );
    if (subtotalLocal <= 0) { setOdPreview(null); return; }
    const handle = setTimeout(async () => {
      setOdPreviewLoading(true);
      try {
        const qs = new URLSearchParams({
          subtotal: String(subtotalLocal),
          discount: String(odDiscount || 0),
          service_charge_percent: String(odSvcPct || 0),
          gst_percent: String(odGstPct || 0),
          apply_gst: odApplyGst ? '1' : '0',
        });
        if (odCustomer.phone) qs.set('customer_phone', odCustomer.phone);
        const res = await fetch(
          `/api/restaurant/${restaurantId}/invoices/preview-totals?${qs.toString()}`,
          { headers: { 'Authorization': `Bearer ${token}` } }
        );
        if (res.ok) setOdPreview(await res.json());
        else setOdPreview(null);
      } catch { setOdPreview(null); }
      finally { setOdPreviewLoading(false); }
    }, 300);
    return () => clearTimeout(handle);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showOnDemandModal, restaurantId, odInvoiceItems, odCustomer.phone, odDiscount, odSvcPct, odGstPct, odApplyGst]);

  // Reset the cart + filters every time the modal opens. Without this,
  // an aborted/closed invoice carries items into the next session,
  // surprising the next cashier. The empty `[]` initial state pairs
  // with the new tap-to-add UI where there's no "empty row" placeholder.
  // odCustomer is intentionally NOT reset — a cashier may type the
  // name first and then start tapping tiles.
  useEffect(() => {
    if (!showOnDemandModal) return;
    setOdInvoiceItems([]);
    setOdCategoryFilter('ALL');
    setOdTileSearch('');
    setShowCustomItemForm(false);
    setCustomItemDraft({ name: '', qty: 1, price: 0 });
    setOdDiscount(0);
    setOdSvcPct(0);  // pre-populated below once tax-config loads
    setOdApplyGst(false);
    setOdSaveError('');
    // Fetch the active tax lines so the layout below knows immediately
    // whether the tenant is on tax_config (auto-applied taxes card) or
    // on the legacy single-GST flow (three editable inputs).
    fetchActiveTaxLines();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showOnDemandModal]);

  // Phase H3 — pre-populate the editable Service Charge % from the tenant
  // default once the tax-config fetch resolves. Runs whenever the modal
  // opens AND when the tenant default loads. Doesn't fight a value the
  // staff has already typed (only sets when odSvcPct is 0 — the initial
  // state from the reset effect above).
  useEffect(() => {
    if (!showOnDemandModal) return;
    if (tenantServiceChargePct <= 0) return;
    if (odSvcPct > 0) return;
    setOdSvcPct(tenantServiceChargePct);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showOnDemandModal, tenantServiceChargePct]);

  // Type-ahead state for the Edit-Invoice modal (separate from the New-Invoice modal)
  const [invEditSearchActive, setInvEditSearchActive] = useState<number | null>(null);
  // Settings save UX — "Saving…" button + "✓ Saved" banner for 3s
  const [settingsSaveStatus, setSettingsSaveStatus] = useState<'idle'|'saving'|'saved'|'error'>('idle');
  // ── Invoice Delete Modal State (admin-gated feature) ──────────────────────
  const [deleteInvoiceTarget, setDeleteInvoiceTarget] = useState<any|null>(null);
  const [deleteIdConfirm, setDeleteIdConfirm]         = useState('');
  const [deleteReason, setDeleteReason]               = useState('');
  const [deletingInvoice, setDeletingInvoice]         = useState(false);
  const [deleteError, setDeleteError]                 = useState<string|null>(null);
  // ── Invoice Edit Modal State ──────────────────────────────────────────────
  const [invoiceEditTarget, setInvoiceEditTarget] = useState<any|null>(null);
  const [invEdit, setInvEdit] = useState<{
    items: {name:string; quantity:number; price:number}[];
    discount: number; svcPct: number; gstPct: number; applyGst: boolean;
    payMethod: 'CASH'|'CARD'|'UPI'; saving: boolean; markingPaid: boolean;
  }>({ items:[], discount:0, svcPct:0, gstPct:0, applyGst:false, payMethod:'CASH', saving:false, markingPaid:false });
  // Server-computed preview for the Edit Invoice modal — surfaces the
  // loyalty discount banner (when the invoice's customer phone matches
  // a loyalty member) and uses the SAME computeInvoiceTotals path as
  // the New Invoice modal so multi-tax (tax_config rows), Section 9(5)
  // ECO splits, and auto-loyalty all stay consistent across both
  // surfaces. Without this, Edit Invoice was rendering totals from
  // its own client-side math which missed loyalty entirely.
  const [invEditPreview, setInvEditPreview] = useState<any | null>(null);
  const [invEditPreviewLoading, setInvEditPreviewLoading] = useState(false);
  // Phase H3 — when tax_config drives the math, blank out the legacy
  // gstPct/applyGst fields (those came pre-populated from the saved
  // invoice's BLENDED `orders.gst_percent` column and would double-count).
  // svcPct is NOT zeroed: service charge is its own editable field now,
  // independent of tax_config statutory taxes. If the saved invoice had
  // a service_charge_percent, we keep it; otherwise the open-invoice
  // load path will populate it from the tenant default (below).
  useEffect(() => {
    const p = invEditPreview;
    if (!p || !Array.isArray(p.taxLines) || p.taxLines.length === 0) return;
    if (invEdit.gstPct === 0 && !invEdit.applyGst) return;
    setInvEdit(prev => ({ ...prev, gstPct: 0, applyGst: false }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [invEditPreview]);

  // Phase H3 — pre-populate svcPct from the tenant default when an Edit
  // Invoice modal opens AND the saved invoice has no service charge of
  // its own. Doesn't fight a value the staff already typed.
  useEffect(() => {
    if (!invoiceEditTarget) return;
    if (tenantServiceChargePct <= 0) return;
    if (invEdit.svcPct > 0) return;
    setInvEdit(prev => ({ ...prev, svcPct: tenantServiceChargePct }));
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [invoiceEditTarget, tenantServiceChargePct]);
  // POS-style tile UI state for the Edit Invoice modal — mirrors the
  // New Invoice modal so a cashier can tap tiles to add items to an
  // existing order invoice (SESSION invoices keep items read-only since
  // they come from customer rounds, not staff entry).
  const [invEditCategoryFilter, setInvEditCategoryFilter] = useState<string>('ALL');
  const [invEditTileSearch, setInvEditTileSearch]         = useState<string>('');
  const [invEditShowCustomForm, setInvEditShowCustomForm] = useState(false);
  const [invEditCustomDraft, setInvEditCustomDraft]       = useState<{name:string;qty:number;price:number}>({name:'',qty:1,price:0});
  // Reset filters/search whenever a new invoice is opened for editing.
  // Keeps the previous edit's category/search from carrying over.
  useEffect(() => {
    if (!invoiceEditTarget) return;
    setInvEditCategoryFilter('ALL');
    setInvEditTileSearch('');
    setInvEditShowCustomForm(false);
    setInvEditCustomDraft({ name: '', qty: 1, price: 0 });
    // Fetch the active tax lines (same store the New Invoice modal uses)
    // so the Edit modal lays out correctly the moment it opens.
    fetchActiveTaxLines();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [invoiceEditTarget]);
  useEffect(() => {
    if (!invoiceEditTarget || !restaurantId) { setInvEditPreview(null); return; }
    const inv = invoiceEditTarget;
    const isSess = !!inv.isSession;
    const subtotalLocal = isSess
      ? Number(inv.raw_subtotal || 0)
      : invEdit.items.reduce((s, it) => s + Number(it.price || 0) * Number(it.quantity || 1), 0);
    if (subtotalLocal <= 0) { setInvEditPreview(null); return; }
    const handle = setTimeout(async () => {
      setInvEditPreviewLoading(true);
      try {
        const qs = new URLSearchParams({
          subtotal: String(subtotalLocal),
          discount: String(invEdit.discount || 0),
          service_charge_percent: String(invEdit.svcPct || 0),
          gst_percent: String(invEdit.gstPct || 0),
          apply_gst: invEdit.applyGst ? '1' : '0',
        });
        const phone = inv.customerPhone || inv.customer_phone;
        if (phone) qs.set('customer_phone', phone);
        const res = await fetch(
          `/api/restaurant/${restaurantId}/invoices/preview-totals?${qs.toString()}`,
          { headers: { 'Authorization': `Bearer ${token}` } }
        );
        if (res.ok) setInvEditPreview(await res.json());
        else setInvEditPreview(null);
      } catch { setInvEditPreview(null); }
      finally { setInvEditPreviewLoading(false); }
    }, 300);
    return () => clearTimeout(handle);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [invoiceEditTarget, restaurantId, invEdit.items, invEdit.discount, invEdit.svcPct, invEdit.gstPct, invEdit.applyGst]);

  // ── Invoice Management State ──────────────────────────────────────────────
  const [invoiceOrder, setInvoiceOrder]       = useState<any | null>(null);
  const [invoiceMode, setInvoiceMode]         = useState<'view' | 'edit'>('view');
  const [invoiceItems, setInvoiceItems]       = useState<any[]>([]);
  const [invoiceDiscount, setInvoiceDiscount]           = useState(0);
  const [invoiceServiceCharge, setInvoiceServiceCharge] = useState(0);   // %
  const [invoiceGstPercent, setInvoiceGstPercent]       = useState(0);   // %
  const [invoiceApplyGst, setInvoiceApplyGst]           = useState(true);
  const [savingInvoice, setSavingInvoice]               = useState(false);
  const [addItemForm, setAddItemForm]                   = useState({ name: '', price: '', quantity: '1' });
  // Payment table sort + search
  const [paymentSearch, setPaymentSearch]               = useState('');
  const [paymentSort, setPaymentSort]                   = useState<{ col: string; dir: 'asc' | 'desc' }>({ col: 'createdAt', dir: 'desc' });

  // ── Pagination + extra filter state for all tables ────────────────────────
  const [ordersPage, setOrdersPage]           = useState(1);
  const [ordersDateFrom, setOrdersDateFrom]   = useState('');
  const [ordersDateTo, setOrdersDateTo]       = useState('');
  const [invoicesPage, setInvoicesPage]       = useState(1);
  const [staffSearch, setStaffSearch]         = useState('');
  const [staffRoleFilter, setStaffRoleFilter] = useState<string>('ALL');

  // ── Staff role metadata ─────────────────────────────────────────────
  // Single source of truth for Staff Management dropdowns / filters / chips.
  //   scope = which property type a role applies to:
  //     RESTAURANT — Chef, Waiter (restaurant-only)
  //     HOTEL      — Front Desk, Housekeeping, Maintenance, Concierge
  //     BOTH       — Manager (works across both modules)
  // The visible-roles helper below filters by the tenant's enabled modules
  // so a restaurant-only tenant never sees hotel roles.
  const STAFF_ROLE_META: Array<{
    id: UserRole; label: string; emoji: string;
    scope: 'BOTH' | 'RESTAURANT' | 'HOTEL';
    chipBg: string; chipText: string; cardBg: string;
  }> = [
    { id: 'CHEF',         label: 'Chef',         emoji: '👨‍🍳', scope: 'RESTAURANT', chipBg: 'bg-orange-200', chipText: 'text-orange-800', cardBg: 'bg-orange-50' },
    { id: 'WAITER',       label: 'Waiter',       emoji: '🧑‍🍽️', scope: 'RESTAURANT', chipBg: 'bg-blue-200',   chipText: 'text-blue-800',   cardBg: 'bg-blue-50' },
    { id: 'MANAGER',      label: 'Manager',      emoji: '🧑‍💼', scope: 'BOTH',       chipBg: 'bg-purple-200', chipText: 'text-purple-800', cardBg: 'bg-purple-50' },
    { id: 'FRONT_DESK',   label: 'Front Desk',   emoji: '🛎️',  scope: 'HOTEL',      chipBg: 'bg-amber-200',  chipText: 'text-amber-800',  cardBg: 'bg-amber-50' },
    { id: 'HOUSEKEEPING', label: 'Housekeeping', emoji: '🛏️',  scope: 'HOTEL',      chipBg: 'bg-teal-200',   chipText: 'text-teal-800',   cardBg: 'bg-teal-50' },
    { id: 'MAINTENANCE',  label: 'Maintenance',  emoji: '🔧',   scope: 'HOTEL',      chipBg: 'bg-slate-200',  chipText: 'text-slate-800',  cardBg: 'bg-slate-50' },
    { id: 'CONCIERGE',    label: 'Concierge',    emoji: '🎩',   scope: 'HOTEL',      chipBg: 'bg-rose-200',   chipText: 'text-rose-800',   cardBg: 'bg-rose-50' },
  ];
  // Roles visible in this tenant — based on whether Hotel + Restaurant
  // modules are active. BOTH roles always show. Other scopes show
  // only when their module is active for this tenant.
  const visibleStaffRoles = STAFF_ROLE_META.filter(r =>
    r.scope === 'BOTH' ||
    (r.scope === 'RESTAURANT' && isRestaurantEnabled) ||
    (r.scope === 'HOTEL'      && isHotelEnabled)
  );
  const staffRoleMetaFor = (role: string) =>
    STAFF_ROLE_META.find(r => r.id === role) ||
    { id: role as UserRole, label: role, emoji: '👤', scope: 'BOTH' as const, chipBg: 'bg-zinc-200', chipText: 'text-zinc-700', cardBg: 'bg-zinc-50' };
  const [staffPage, setStaffPage]             = useState(1);
  const [editingStaff, setEditingStaff]       = useState<any | null>(null);
  // Phase B3 — cross-location staff transfer
  const [transferringStaff, setTransferringStaff] = useState<any | null>(null);
  const [isBulkAddingStaff, setIsBulkAddingStaff] = useState(false);
  const [bulkRows, setBulkRows] = useState<Array<{name: string; role: UserRole; loginId: string; password: string; phone: string; email: string}>>([
    { name: '', role: 'MANAGER', loginId: '', password: '', phone: '', email: '' },
    { name: '', role: 'MANAGER', loginId: '', password: '', phone: '', email: '' },
    { name: '', role: 'MANAGER', loginId: '', password: '', phone: '', email: '' },
  ]);
  const [feedbackSearch, setFeedbackSearch]   = useState('');
  const [feedbackMinRating, setFeedbackMinRating] = useState(0);
  const [feedbackSortDir, setFeedbackSortDir] = useState<'asc'|'desc'>('desc');
  const [feedbackPage, setFeedbackPage]       = useState(1);

  const [editingItem, setEditingItem] = useState<MenuItem | null>(null);
  const [editImageFile, setEditImageFile] = useState<File | null>(null);
  // Default role MANAGER — works for any tenant (RESTAURANT / HOTEL / BOTH).
  // Restaurant-only tenants will pick Chef/Waiter; hotel-only tenants will
  // pick Front Desk / Housekeeping / etc.
  const [newStaff, setNewStaff] = useState({ loginId: '', name: '', password: '', role: 'MANAGER' as UserRole, phone: '', email: '', hourly_rate: 0, payroll_id: '' });
  const [newItem, setNewItem] = useState<{
    name: string,
    description: string,
    price: string,
    price_half: string,
    price_full: string,
    category: string,
    imageFile: File | null,
    driveUrl: string,
    dietary_type: DietaryType,
    is_daily_special: boolean,
    // When true: this is a "Special" item whose price is set at
    // billing (e.g. market-rate seafood). Saves price=0; the
    // cashier MUST enter a price in the cart at invoice time.
    price_tbd: boolean
  }>({
    name: '',
    description: '',
    price: '',
    price_half: '',
    price_full: '',
    category: 'Mains',
    imageFile: null,
    dietary_type: 'VEG',
    is_daily_special: false,
    price_tbd: false
  });

  // Fetch role-based tab permissions
  useEffect(() => {
    fetch(`/api/restaurant/${restaurantId}/my-permissions`, {
      headers: { 'Authorization': `Bearer ${token}` }
    })
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (data && data.allowed_tabs && Array.isArray(data.allowed_tabs) && data.allowed_tabs.length > 0) {
          setAllowedTabs(data.allowed_tabs);
        }
      })
      .catch(() => {});
  }, [restaurantId, token]);

  // Fetch owner's own profile (name, email, phone) for SETTINGS tab
  const fetchOwnerProfile = async () => {
    try {
      const res = await fetch('/api/owner/profile', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      if (res.ok) {
        const data = await res.json();
        setOwnerProfile({ name: data.name || '', email: data.email || '', phone: data.phone || '' });
      }
    } catch (err) {
      console.error('Failed to fetch owner profile:', err);
    }
  };

  const updateOwnerProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setProfileSaving(true);
    try {
      const res = await fetch('/api/owner/profile', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify(ownerProfile)
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to update profile');
      setProfileSaved(true);
      setTimeout(() => setProfileSaved(false), 3000);
    } catch (err: any) {
      alert(err.message);
    } finally {
      setProfileSaving(false);
    }
  };

  useEffect(() => {
    if (!restaurantId || restaurantId === 'null' || restaurantId === 'undefined') return;
    fetchMenu();
    fetchReports();
    fetchRestaurant();
    fetchTables();
    fetchStaff();
    fetchOrders();
    fetchOwnerProfile();
    if (activeTab === 'FEEDBACK') fetchFeedback();
    if (activeTab === 'NOTIFICATIONS') fetchNotificationSettings();
    if (activeTab === 'MONITOR') fetchLiveTables();
    if (activeTab === 'INVOICES') fetchInvoices();
    if (activeTab === 'INVENTORY') fetchInventoryForSubTab();
    if (activeTab === 'DELIVERY') fetchDeliveryForSubTab();

    const interval = setInterval(() => {
      fetchOrders();
      if (activeTab === 'REPORTS') fetchReports();
      if (activeTab === 'MONITOR') fetchLiveTables();
      if (activeTab === 'INVOICES') fetchInvoices();
      // 30s auto-refresh for the live platform-orders feed when on DELIVERY tab
      if (activeTab === 'DELIVERY' && deliverySubTab === 'LIVE_ORDERS') fetchDeliveryOrders();
    }, 30000);

    // Per-second clock tick — only needed on MONITOR tab (live visit timers).
    // Running this on other tabs caused every child component to re-render
    // every second, which in turn made Framer-Motion entry animations flash
    // on Analytics KPI cards (they were unmount/remount due to nested
    // component definition).
    let clockTick: ReturnType<typeof setInterval> | undefined;
    if (activeTab === 'MONITOR') {
      clockTick = setInterval(() => setLiveNow(Date.now()), 1000);
    }

    return () => {
      clearInterval(interval);
      if (clockTick) clearInterval(clockTick);
    };
  }, [restaurantId, activeTab]);

  // Refetch inventory when sub-tab changes
  useEffect(() => {
    if (activeTab === 'INVENTORY') fetchInventoryForSubTab();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [inventorySubTab, poFilter]);

  // Refetch delivery data when sub-tab or filter changes
  useEffect(() => {
    if (activeTab === 'DELIVERY') fetchDeliveryForSubTab();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [deliverySubTab, deliveryFilter.platform, deliveryFilter.status]);

  // Refetch dashboard when horizon toggles (Daily / Weekly / Monthly)
  useEffect(() => {
    if (activeTab === 'INVENTORY' && inventorySubTab === 'DASHBOARD') {
      fetchInventoryDashboard();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [forecastHorizon]);

  // ── Invoice helpers ───────────────────────────────────────────────────────
  const openInvoice = async (order: any, mode: 'view' | 'edit' = 'view') => {
    // Fetch fresh invoice detail (includes discount_amount + apply_gst)
    try {
      const res = await fetch(`/api/restaurant/${restaurantId}/orders/${order.id}/invoice`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      const data = await res.json();
      const items = Array.isArray(data.items) ? data.items : [];
      setInvoiceOrder({ ...order, ...data });
      setInvoiceItems(items.map((it: any) => ({ ...it })));
      setInvoiceDiscount(Number(data.discount_amount || 0));
      setInvoiceServiceCharge(Number(data.service_charge_percent || 0));
      setInvoiceGstPercent(Number(data.gst_percent ?? restaurant?.gst_percentage ?? 0));
      setInvoiceApplyGst(Number(data.apply_gst ?? 0) !== 0);
      setInvoiceMode(mode);
      setAddItemForm({ name: '', price: '', quantity: '1' });
    } catch {
      // Fallback to local data
      const items = Array.isArray(order.items) ? order.items : [];
      setInvoiceOrder(order);
      setInvoiceItems(items.map((it: any) => ({ ...it })));
      setInvoiceDiscount(Number(order.discount_amount || 0));
      setInvoiceServiceCharge(Number(order.service_charge_percent || 0));
      setInvoiceGstPercent(Number(restaurant?.gst_percentage ?? 0));
      setInvoiceApplyGst(Boolean(restaurant?.is_gst_enabled));
      setInvoiceMode(mode);
      setAddItemForm({ name: '', price: '', quantity: '1' });
    }
  };

  const closeInvoice = () => { setInvoiceOrder(null); setInvoiceMode('view'); };

  const saveInvoice = async () => {
    if (!invoiceOrder) return;
    setSavingInvoice(true);
    try {
      const res = await fetch(`/api/restaurant/${restaurantId}/orders/${invoiceOrder.id}/invoice`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${token}` },
        body: JSON.stringify({ items: invoiceItems, discount_amount: invoiceDiscount, service_charge_percent: invoiceServiceCharge, gst_percent: invoiceGstPercent, apply_gst: invoiceApplyGst ? 1 : 0 }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Failed to save');
      setOrders(prev => prev.map(o => o.id === invoiceOrder.id
        ? { ...o, totalAmount: data.total, gstAmount: data.gst_amount, items: invoiceItems, discount_amount: invoiceDiscount }
        : o
      ));
      setInvoiceOrder((prev: any) => prev ? { ...prev, totalAmount: data.total, gstAmount: data.gst_amount } : null);
      setInvoiceMode('view');
    } catch (err: any) {
      console.error('Save invoice error:', err.message);
    } finally {
      setSavingInvoice(false);
    }
  };

  const printInvoiceOrder = (
    order: any, items: any[], discount: number, applyGst: boolean,
    serviceChargePct: number = 0, gstPct: number = 0
  ) => {
    const dt            = new Date(order.createdAt || order.created_at || Date.now());
    const rawSubtotal   = items.reduce((s, it) => s + Number(it.price || 0) * Number(it.quantity || 1), 0);
    const afterDiscount = Math.max(0, rawSubtotal - discount);
    const svcAmt        = afterDiscount * serviceChargePct / 100;
    const taxable       = afterDiscount + svcAmt;
    const effGstRate    = applyGst ? gstPct : 0;
    const gstAmt        = taxable * effGstRate / 100;
    const total         = taxable + gstAmt;
    const html = buildThermalHTML({
      restaurantName:       restaurant?.name || 'Restaurant',
      gstin:                restaurant?.gst_number,
      gstEnabled:           applyGst && effGstRate > 0,
      gstPercent:           effGstRate,
      billId:               (order.id || '').slice(-8).toUpperCase(),
      tableName:            order.tableNumber || order.table_number || undefined,
      customerName:         order.customerName || order.customer_name || undefined,
      customerPhone:        order.customerPhone || order.customer_phone || undefined,
      date:                 dt.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }),
      time:                 dt.toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit' }),
      rounds:               [{ items: items.map(it => ({ name: it.name || it.item_name || '', qty: Number(it.quantity || 1), price: Number(it.price || 0) })) }],
      subtotal:             afterDiscount,
      discountAmount:       discount > 0 ? discount : undefined,
      serviceChargeAmount:  svcAmt > 0 ? svcAmt : undefined,
      serviceChargePercent: serviceChargePct > 0 ? serviceChargePct : undefined,
      gstAmount:            gstAmt,
      total,
      paymentMethod:        order.paymentMethod || order.payment_method || undefined,
    });
    openThermalPrint(html);
  };

